//! Native (rlib) walker tests against the CHECKED-IN extracted topologies of
//! the `.gg` reference fixtures.
//!
//! Fixture provenance: `tests/fixtures/*.topology.json` are the serde JSON of
//! the `GgTopology` produced by
//! `gnosis_polyglot::parse_and_extract_orchestration` over
//! `open-source/gnosis/gnode/benchmarks/{fanout.gg,echo.gg}` (this crate must
//! not depend on gnosis-polyglot — tree-sitter can't build for wasm32, and
//! the rlib is compiled for both targets). Drift is caught by
//! `polyglot/tests/gg_embed_correctness.rs::checked_in_fixture_topologies_match_extractor`;
//! regenerate with the `regen_walker_fixtures` test documented there.
//!
//! Expected values are gnexec's observed outputs (verified 2026-07-03):
//!   gnexec fanout.gg --export app  --input-json '{"userId":"ada"}' → ada:user|ada:profile
//!   gnexec echo.gg   --export echo --input-json '{"name":"ada"}'   → null

use gg_walker_wasm::{run_envelope_bytes, run_topology, validate_topology_json, Topology};
use serde_json::{json, Value};

fn fixture(name: &str) -> String {
    let path = format!("{}/tests/fixtures/{name}", env!("CARGO_MANIFEST_DIR"));
    std::fs::read_to_string(&path).unwrap_or_else(|e| panic!("read {path}: {e}"))
}

fn fanout() -> Topology {
    serde_json::from_str(&fixture("fanout.gg.topology.json")).expect("fanout fixture parses")
}

fn echo() -> Topology {
    serde_json::from_str(&fixture("echo.gg.topology.json")).expect("echo fixture parses")
}

#[test]
fn fanout_matches_gnexec() {
    let out = run_topology(&fanout(), &json!({"userId": "ada"})).expect("fanout walks");
    assert_eq!(out, Value::String("ada:user|ada:profile".into()));

    let out = run_topology(&fanout(), &json!({"userId": "x-1"})).expect("fanout walks");
    assert_eq!(out, Value::String("x-1:user|x-1:profile".into()));
}

#[test]
fn echo_matches_gnexec_null() {
    // echo.gg is a property-free TsBridge chain; gnexec walks it as no-ops
    // and prints null. So does the walker.
    let out = run_topology(&echo(), &json!({"name": "ada"})).expect("echo walks");
    assert_eq!(out, Value::Null);
}

#[test]
fn fixtures_validate_statically() {
    validate_topology_json(&fixture("fanout.gg.topology.json")).expect("fanout admits");
    validate_topology_json(&fixture("echo.gg.topology.json")).expect("echo admits");
}

#[test]
fn envelope_round_trip() {
    let envelope = format!(
        r#"{{"topology":{},"input":{{"userId":"ada"}}}}"#,
        fixture("fanout.gg.topology.json")
    );
    let out = run_envelope_bytes(envelope.as_bytes()).expect("envelope runs");
    assert_eq!(out, r#""ada:user|ada:profile""#);
}

// ── Fail-closed (decline) cases ──────────────────────────────────────

#[test]
fn missing_user_id_declines() {
    assert!(run_topology(&fanout(), &json!({})).is_err());
    // gnexec would stringify a numeric userId; the walker declines instead
    // (trapping where the reference answers is safe; see crate docs).
    assert!(run_topology(&fanout(), &json!({"userId": 7})).is_err());
}

#[test]
fn unknown_label_declines() {
    let mut t = fanout();
    t.nodes[0].labels = vec!["MysteryNode".to_string()];
    let err = run_topology(&t, &json!({"userId": "ada"})).unwrap_err();
    assert!(err.0.contains("certified") || err.0.contains("Entry"), "{err}");
}

#[test]
fn unknown_callee_declines() {
    let mut t = fanout();
    for node in &mut t.nodes {
        if node.properties.get("callee").map(String::as_str) == Some("merge") {
            node.properties
                .insert("callee".to_string(), "fetchRemote".to_string());
        }
    }
    let err = run_topology(&t, &json!({"userId": "ada"})).unwrap_err();
    assert!(err.0.contains("fetchRemote"), "{err}");
}

#[test]
fn uncertified_branch_callee_declines() {
    let mut t = fanout();
    for node in &mut t.nodes {
        if node.properties.get("callee").map(String::as_str) == Some("loadProfile") {
            node.properties
                .insert("callee".to_string(), "loadSecrets".to_string());
        }
    }
    assert!(run_topology(&t, &json!({"userId": "ada"})).is_err());
}

#[test]
fn race_edge_declines() {
    let mut t = fanout();
    for edge in &mut t.edges {
        if edge.edge_type == "Fork" {
            edge.edge_type = "Race".to_string();
        }
    }
    assert!(run_topology(&t, &json!({"userId": "ada"})).is_err());
}

#[test]
fn bridge_marker_with_properties_declines() {
    let mut t = echo();
    for node in &mut t.nodes {
        if node.labels.iter().any(|l| l == "TsBridgeCall") {
            node.properties
                .insert("callee".to_string(), "greet".to_string());
        }
    }
    assert!(run_topology(&t, &json!({"name": "ada"})).is_err());
}

#[test]
fn fold_without_merge_then_uncarried_return_declines() {
    // Return expr that isn't property-carried (raw source expression).
    let mut t = fanout();
    for node in &mut t.nodes {
        if node.labels.iter().any(|l| l == "Return") {
            node.properties
                .insert("expr".to_string(), "user + '|' + profile".to_string());
        }
    }
    assert!(run_topology(&t, &json!({"userId": "ada"})).is_err());
}
